# Evaluation harness run
import statistics

def run_evaluation(model_client, eval_registry, suite_version: str, model_id: str) -> dict:
    """Run evaluation suite against a model and record results."""
    examples = eval_registry.get_suite(suite_version)
    assert all(e["contamination_status"] == "clean" for e in examples),         "Evaluation suite contains contaminated examples"

    results = {"model_id": model_id, "suite_version": suite_version, "by_axis": {}, "by_example": {}}
    axis_scores = {}

    for example in examples:
        response = model_client.complete(example["prompt"])
        passed = evaluate_response(response, example["reference_answer"], example["acceptable_answers"])
        score = 1.0 if passed else 0.0

        results["by_example"][example["example_id"]] = {"passed": passed, "score": score}
        for axis in example["axes"]:
            axis_scores.setdefault(axis, []).append(score)

    for axis, scores in axis_scores.items():
        results["by_axis"][axis] = {
            "mean": statistics.mean(scores),
            "n": len(scores),
            "pass_rate": sum(1 for s in scores if s > 0) / len(scores),
        }

    # eval_registry.record_run(results)  # persist
    return results

def evaluate_response(response: str, reference: str, acceptable: list[str]) -> bool:
    """Check if model response matches reference or any acceptable answer."""
    norm = lambda s: s.strip().lower()
    candidates = [reference] + acceptable
    return any(norm(response) == norm(c) for c in candidates)
